"""
Pytest test suite for Encounter closing and post-close modification rules.

Requirement:
    A clinician shall close an Encounter; closed Encounters shall reject further
    modifications except for addendum Observations. Negative paths including
    permission denial, missing mandatory elements, and conflicting state
    transitions must be tested.
"""

import uuid
from datetime import datetime, timezone
from unittest.mock import MagicMock, patch

import pytest

# ---------------------------------------------------------------------------
# Domain model stubs (replace with real imports in your project)
# ---------------------------------------------------------------------------

class EncounterStatus:
    PLANNED = "planned"
    IN_PROGRESS = "in-progress"
    CLOSED = "closed"
    CANCELLED = "cancelled"
    ENTERED_IN_ERROR = "entered-in-error"


class ObservationType:
    STANDARD = "standard"
    ADDENDUM = "addendum"


class Permission:
    CLOSE_ENCOUNTER = "encounter:close"
    MODIFY_ENCOUNTER = "encounter:modify"
    ADD_OBSERVATION = "observation:add"
    ADD_ADDENDUM = "observation:addendum"


class PermissionDeniedError(Exception):
    """Raised when the actor lacks required permissions."""


class EncounterClosedError(Exception):
    """Raised when attempting to modify a closed Encounter (non-addendum)."""


class InvalidStateTransitionError(Exception):
    """Raised for illegal status transitions."""


class MissingMandatoryElementError(Exception):
    """Raised when a mandatory element is absent."""


class NotFoundError(Exception):
    """Raised when a resource cannot be located."""


class ConflictingStateError(Exception):
    """Raised when a concurrent or conflicting operation is detected."""


class Observation:
    def __init__(
        self,
        observation_id: str,
        encounter_id: str,
        obs_type: str,
        code: str | None,
        value: str | None,
        authored_by: str,
    ):
        self.observation_id = observation_id
        self.encounter_id = encounter_id
        self.obs_type = obs_type
        self.code = code
        self.value = value
        self.authored_by = authored_by
        self.created_at = datetime.now(timezone.utc)


class Encounter:
    """
    Lightweight Encounter aggregate.

    Real implementations would persist to a database; here we keep everything
    in-memory so tests remain fast and deterministic.
    """

    ALLOWED_CLOSE_TRANSITIONS = {EncounterStatus.IN_PROGRESS}

    def __init__(
        self,
        encounter_id: str,
        patient_id: str,
        status: str = EncounterStatus.IN_PROGRESS,
    ):
        self.encounter_id = encounter_id
        self.patient_id = patient_id
        self.status = status
        self.close_reason: str | None = None
        self.closed_by: str | None = None
        self.closed_at: datetime | None = None
        self.observations: list[Observation] = []
        self._version = 1  # optimistic-locking token

    # ------------------------------------------------------------------
    # Commands
    # ------------------------------------------------------------------

    def close(
        self,
        actor: "Clinician",
        reason: str | None = None,
        expected_version: int | None = None,
    ) -> None:
        """Close this Encounter."""
        if not actor.has_permission(Permission.CLOSE_ENCOUNTER):
            raise PermissionDeniedError(
                f"Actor '{actor.clinician_id}' lacks '{Permission.CLOSE_ENCOUNTER}'."
            )

        if self.status not in self.ALLOWED_CLOSE_TRANSITIONS:
            raise InvalidStateTransitionError(
                f"Cannot close an Encounter in '{self.status}' status."
            )

        if expected_version is not None and expected_version != self._version:
            raise ConflictingStateError(
                "Optimistic lock failure: version mismatch."
            )

        self.status = EncounterStatus.CLOSED
        self.close_reason = reason
        self.closed_by = actor.clinician_id
        self.closed_at = datetime.now(timezone.utc)
        self._version += 1

    def modify(self, actor: "Clinician", **fields) -> None:
        """Generic field update — forbidden once closed."""
        if not actor.has_permission(Permission.MODIFY_ENCOUNTER):
            raise PermissionDeniedError(
                f"Actor '{actor.clinician_id}' lacks '{Permission.MODIFY_ENCOUNTER}'."
            )

        if self.status == EncounterStatus.CLOSED:
            raise EncounterClosedError(
                "Closed Encounters cannot be modified directly. "
                "Use an addendum Observation instead."
            )

        for key, val in fields.items():
            setattr(self, key, val)
        self._version += 1

    def add_observation(
        self,
        actor: "Clinician",
        code: str | None,
        value: str | None,
        obs_type: str = ObservationType.STANDARD,
    ) -> Observation:
        """
        Attach an Observation to this Encounter.

        * STANDARD observations are blocked on closed Encounters.
        * ADDENDUM observations are always allowed (with correct permission).
        """
        if obs_type == ObservationType.ADDENDUM:
            if not actor.has_permission(Permission.ADD_ADDENDUM):
                raise PermissionDeniedError(
                    f"Actor '{actor.clinician_id}' lacks '{Permission.ADD_ADDENDUM}'."
                )
        else:
            if not actor.has_permission(Permission.ADD_OBSERVATION):
                raise PermissionDeniedError(
                    f"Actor '{actor.clinician_id}' lacks '{Permission.ADD_OBSERVATION}'."
                )
            if self.status == EncounterStatus.CLOSED:
                raise EncounterClosedError(
                    "Standard Observations cannot be added to a closed Encounter."
                )

        # Mandatory-element validation
        if code is None:
            raise MissingMandatoryElementError("Observation 'code' is mandatory.")
        if value is None:
            raise MissingMandatoryElementError("Observation 'value' is mandatory.")

        obs = Observation(
            observation_id=str(uuid.uuid4()),
            encounter_id=self.encounter_id,
            obs_type=obs_type,
            code=code,
            value=value,
            authored_by=actor.clinician_id,
        )
        self.observations.append(obs)
        return obs


class Clinician:
    def __init__(self, clinician_id: str, permissions: set[str] | None = None):
        self.clinician_id = clinician_id
        self._permissions: set[str] = permissions or set()

    def has_permission(self, permission: str) -> bool:
        return permission in self._permissions

    def grant(self, *permissions: str) -> None:
        self._permissions.update(permissions)

    def revoke(self, *permissions: str) -> None:
        self._permissions.difference_update(permissions)


