class TestCloseEncounterHappyPath:

    def test_clinician_can_close_in_progress_encounter(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        open_encounter.close(actor=full_clinician, reason="Visit complete")

        assert open_encounter.status == EncounterStatus.CLOSED
        assert open_encounter.close_reason == "Visit complete"
        assert open_encounter.closed_by == full_clinician.clinician_id
        assert open_encounter.closed_at is not None

    def test_close_records_timestamp_in_utc(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        before = datetime.now(timezone.utc)
        open_encounter.close(actor=full_clinician)
        after = datetime.now(timezone.utc)

        assert before <= open_encounter.closed_at <= after
        assert open_encounter.closed_at.tzinfo == timezone.utc

    def test_close_increments_version(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        original_version = open_encounter._version
        open_encounter.close(actor=full_clinician)

        assert open_encounter._version == original_version + 1

    def test_close_without_reason_is_allowed(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        open_encounter.close(actor=full_clinician)

        assert open_encounter.status == EncounterStatus.CLOSED
        assert open_encounter.close_reason is None

    def test_close_records_correct_clinician_id(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        open_encounter.close(actor=full_clinician)

        assert open_encounter.closed_by == "clinician-001"


