class TestCloseEncounterPermissionDenied:

    def test_actor_without_close_permission_cannot_close(
        self, open_encounter: Encounter, restricted_clinician: Clinician
    ):
        with pytest.raises(PermissionDeniedError, match=Permission.CLOSE_ENCOUNTER):
            open_encounter.close(actor=restricted_clinician)

    def test_actor_with_only_modify_permission_cannot_close(
        self, open_encounter: Encounter
    ):
        clinician = Clinician(
            "clinician-modify-only",
            permissions={Permission.MODIFY_ENCOUNTER},
        )
        with pytest.raises(PermissionDeniedError):
            open_encounter.close(actor=clinician)

    def test_encounter_remains_open_after_permission_denied(
        self, open_encounter: Encounter, restricted_clinician: Clinician
    ):
        original_status = open_encounter.status
        with pytest.raises(PermissionDeniedError):
            open_encounter.close(actor=restricted_clinician)

        assert open_encounter.status == original_status

    def test_permission_denial_does_not_alter_version(
        self, open_encounter: Encounter, restricted_clinician: Clinician
    ):
        original_version = open_encounter._version
        with pytest.raises(PermissionDeniedError):
            open_encounter.close(actor=restricted_clinician)

        assert open_encounter._version == original_version


