class TestCloseEncounterInvalidStateTransitions:

    def test_cannot_close_already_closed_encounter(
        self, closed_encounter: Encounter, full_clinician: Clinician
    ):
        with pytest.raises(InvalidStateTransitionError, match="closed"):
            closed_encounter.close(actor=full_clinician)

    def test_cannot_close_planned_encounter(
        self, planned_encounter: Encounter, full_clinician: Clinician
    ):
        with pytest.raises(InvalidStateTransitionError, match="planned"):
            planned_encounter.close(actor=full_clinician)

    def test_cannot_close_cancelled_encounter(
        self, cancelled_encounter: Encounter, full_clinician: Clinician
    ):
        with pytest.raises(InvalidStateTransitionError, match="cancelled"):
            cancelled_encounter.close(actor=full_clinician)

    @pytest.mark.parametrize(
        "bad_status",
        [
            EncounterStatus.CLOSED,
            EncounterStatus.CANCELLED,
            EncounterStatus.PLANNED,
            EncounterStatus.ENTERED_IN_ERROR,
        ],
    )
    def test_close_rejected_for_all_non_in_progress_statuses(
        self, bad_status: str, full_clinician: Clinician
    ):
        enc = Encounter(str(uuid.uuid4()), "patient-x", status=bad_status)
        with pytest.raises(InvalidStateTransitionError):
            enc.close(actor=full_clinician)

    def test_state_unchanged_after_invalid_transition(
        self, planned_encounter: Encounter, full_clinician: Clinician
    ):
        with pytest.raises(InvalidStateTransitionError):
            planned_encounter.close(actor=full_clinician)

        assert planned_encounter.status == EncounterStatus.PLANNED


