class TestCloseEncounterOptimisticLocking:

    def test_close_with_correct_version_succeeds(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        open_encounter.close(
            actor=full_clinician, expected_version=open_encounter._version
        )
        assert open_encounter.status == EncounterStatus.CLOSED

    def test_close_with_stale_version_raises_conflict(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        with pytest.raises(ConflictingStateError, match="version mismatch"):
            open_encounter.close(actor=full_clinician, expected_version=999)

    def test_stale_version_does_not_change_status(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        with pytest.raises(ConflictingStateError):
            open_encounter.close(actor=full_clinician, expected_version=999)

        assert open_encounter.status == EncounterStatus.IN_PROGRESS


