        with pytest.raises(EncounterClosedError):
            closed_encounter.modify(
                actor=full_clinician, patient_id="should-not-apply"
            )

        assert closed_encounter.patient_id == original_patient_id

    def test_modify_open_encounter_succeeds(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        open_encounter.modify(actor=full_clinician, patient_id="patient-updated")

        assert open_encounter.patient_id == "patient-updated"

    def test_modify_without_permission_raises_error_before_status_check(
        self, closed_encounter: Encounter, restricted_clinician: Clinician
    ):
        """Permission denial must be checked before status; raises PermissionDeniedError."""
        with pytest.raises(PermissionDeniedError):
            closed_encounter.modify(
                actor=restricted_clinician, patient_id="patient-updated"
            )

