class TestEdgeCasesAndRegression:

    def test_closing_idempotency_is_not_allowed(
        self, closed_encounter: Encounter, full_clinician: Clinician
    ):
        """Closing an already-closed encounter must raise, not silently succeed."""
        with pytest.raises(InvalidStateTransitionError):
            closed_encounter.close(actor=full_clinician)

    def test_standard_observation_on_open_then_close_then_addendum(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        """Typical workflow: observe → close → addendum."""
        open_encounter.add_observation(
            actor=full_clinician, code="8867-4", value="72"
        )
        open_encounter.close(actor=full_clinician)
        open_encounter.add_observation(
            actor=full_clinician,
            code="11506-3",
            value="Addendum note",
            obs_type=ObservationType.ADDENDUM,
        )

        assert open_encounter.status == EncounterStatus.CLOSED
        assert len(open_encounter.observations) == 2
        assert open_encounter.observations[0].obs_type == ObservationType.STANDARD
        assert open_encounter.observations[1].obs_type == ObservationType.ADDENDUM

    def test_revoking_close_permission_mid_session(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        """If permission is revoked before close, the action must fail."""
        full_clinician.revoke(Permission.CLOSE_ENCOUNTER)

        with pytest.raises(PermissionDeniedError):
            open_encounter.close(actor=full_clinician)

        assert open_encounter.status == EncounterStatus.IN_PROGRESS

    def test_granting_permission_after_failure_allows_close(
        self, open_encounter: Encounter, restricted_clinician: Clinician
    ):
        with pytest.raises(PermissionDeniedError):
            open_encounter.close(actor=restricted_clinician)

        restricted_clinician.grant(Permission.CLOSE_ENCOUNTER)
        open_encounter.close(actor=restricted_clinician)

        assert open_encounter.status == EncounterStatus.CLOSED

    def test_different_clinician_can_add_addendum_to_encounter_closed_by_another(
        self, closed_encounter: Encounter
    ):
        second_clinician = Clinician(
            "clinician-002",
            permissions={Permission.ADD_ADDENDUM},
        )
        obs = closed_encounter.add_observation(
            actor=second_clinician,
            code="11506-3",
            value="Second clinician note",
            obs_type=ObservationType.ADDENDUM,
        )

        assert obs.authored_by == "clinician-002"
        assert obs in closed_encounter.observations

    def test_encounter_version_does_not_increment_on_failed_close(
        self, open_encounter: Encounter, restricted_clinician: Clinician
    ):
        original_version = open_encounter._version
        with pytest.raises(PermissionDeniedError):
            open_encounter.close(actor=restricted_clinician)

        assert open_encounter._version == original_version

    @patch("uuid.uuid4", return_value=MagicMock(hex="fixed-uuid"))
    def test_observation_id_assigned_on_creation(
        self, _mock_uuid, open_encounter: Encounter, full_clinician: Clinician
    ):
        obs = open_encounter.add_observation(
            actor=full_clinician, code="8867-4", value="72"
        )

        assert obs.observation_id is not None
        assert isinstance(obs.observation_id, str)

    def test_close_reason_preserved_exactly(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        reason = "Patient discharged — planned follow-up in 2 weeks."
        open_encounter.close(actor=full_clinician, reason=reason)

        assert open_encounter.close_reason == reason

    def test_empty_string_code_treated_as_present(
        self, open_encounter: Encounter, full_clinician: Clinician
    ):
        """Empty string is not None; validation layer (not tested here) handles it."""
        obs = open_encounter.add_observation(
            actor=full_clinician, code="", value="72"
        )
        assert obs.code == ""

    def test_cancellation_after_close_is_not_permitted(
        self, closed_encounter: Encounter, full_clinician: Clinician
    ):
        """Attempting to transition from CLOSED → CANCELLED via close() must fail."""
        with pytest.raises(InvalidStateTransitionError):
            closed_encounter.close(actor=full_clinician)
